import { useState, useRef, useEffect } from "react";
import { auth, db } from "./firebase-config";
import { createUserWithEmailAndPassword, signInWithEmailAndPassword, signOut, onAuthStateChanged } from "firebase/auth";
import { collection, doc, setDoc, getDoc, getDocs, addDoc, deleteDoc, query, where, onSnapshot, serverTimestamp, orderBy } from "firebase/firestore";

/* ================================================================
   VIVALIEN V4 — App avec Admin + Compagnon + Famille
   ================================================================ */

const LOGO_URL = "data:image/jpeg;base64,";

const moods = {
  "radieuse": { e: "😄", c: "#43A047" }, "joyeuse": { e: "😊", c: "#7CB342" },
  "apaisé": { e: "😌", c: "#1E88E5" }, "apaisée": { e: "😌", c: "#1E88E5" },
  "fatigué": { e: "😴", c: "#FB8C00" }, "fatiguée": { e: "😴", c: "#FB8C00" },
  "triste": { e: "😢", c: "#78909C" },
};
const gm = m => moods[m?.toLowerCase()] || { e: "😊", c: "#7CB342" };
const fd = d => { try { return new Date(d).toLocaleDateString("fr-FR", { weekday: "long", day: "numeric", month: "long" }); } catch(e) { return d; } };

// ================================================================
// MAIN APP
// ================================================================
export default function App() {
  const [user, setUser] = useState(null);
  const [userData, setUserData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [view, setView] = useState("dashboard");
  const [sel, setSel] = useState(null);
  const [reports, setReports] = useState([]);
  const [seniors, setSeniors] = useState([]);
  const [events, setEvents] = useState([]);
  const [companions, setCompanions] = useState([]);
  const [newMode, setNewMode] = useState(false);
  const [addSeniorMode, setAddSeniorMode] = useState(false);
  const [notif, setNotif] = useState(null);

  const toast = m => { setNotif(m); setTimeout(() => setNotif(null), 3000); };
  const nav = v => { setView(v); setSel(null); setNewMode(false); setAddSeniorMode(false); };

  useEffect(() => {
    const unsub = onAuthStateChanged(auth, async (u) => {
      if (u) {
        setUser(u);
        const userDoc = await getDoc(doc(db, "users", u.uid));
        if (userDoc.exists()) setUserData(userDoc.data());
      } else { setUser(null); setUserData(null); }
      setLoading(false);
    });
    return unsub;
  }, []);

  useEffect(() => {
    if (!user || !userData) return;
    const role = userData.role;
    const unsubs = [];

    if (role === "admin") {
      // Admin sees everything
      unsubs.push(onSnapshot(collection(db, "seniors"), snap => setSeniors(snap.docs.map(d => ({ id: d.id, ...d.data() })))));
      unsubs.push(onSnapshot(query(collection(db, "reports"), orderBy("createdAt", "desc")), snap => setReports(snap.docs.map(d => ({ id: d.id, ...d.data() })))));
      unsubs.push(onSnapshot(collection(db, "events"), snap => setEvents(snap.docs.map(d => ({ id: d.id, ...d.data() })))));
      unsubs.push(onSnapshot(query(collection(db, "users"), where("role", "==", "companion")), snap => setCompanions(snap.docs.map(d => ({ id: d.id, ...d.data() })))));
    }

    if (role === "companion") {
      const q1 = query(collection(db, "seniors"), where("companionId", "==", user.uid));
      unsubs.push(onSnapshot(q1, snap => setSeniors(snap.docs.map(d => ({ id: d.id, ...d.data() })))));
      const q2 = query(collection(db, "reports"), where("companionId", "==", user.uid), orderBy("createdAt", "desc"));
      unsubs.push(onSnapshot(q2, snap => setReports(snap.docs.map(d => ({ id: d.id, ...d.data() })))));
      const q3 = query(collection(db, "events"), where("companionId", "==", user.uid));
      unsubs.push(onSnapshot(q3, snap => setEvents(snap.docs.map(d => ({ id: d.id, ...d.data() })))));
    }

    if (role === "family") {
      const q1 = query(collection(db, "seniors"), where("familyEmail", "==", user.email));
      unsubs.push(onSnapshot(q1, snap => {
        const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));
        setSeniors(list);
        if (list.length > 0) {
          const ids = list.map(s => s.id);
          const q2 = query(collection(db, "reports"), where("seniorId", "in", ids), orderBy("createdAt", "desc"));
          unsubs.push(onSnapshot(q2, snap2 => setReports(snap2.docs.map(d => ({ id: d.id, ...d.data() })))));
        }
      }));
    }

    return () => unsubs.forEach(u => u());
  }, [user, userData]);

  if (loading) return <LoadScreen />;
  if (!user) return <AuthScreen toast={toast} />;
  if (!userData) return <LoadScreen />;

  const role = userData.role;
  const rc = { admin: "#6A1B9A", companion: "#2E7D32", family: "#1565C0" }[role] || "#333";

  return (
    <div style={S.app}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@500;700;800&family=Source+Sans+3:wght@300;400;500;600;700&display=swap');
        @keyframes slideDown{from{opacity:0;transform:translate(-50%,-20px)}to{opacity:1;transform:translate(-50%,0)}}
        @keyframes fadeUp{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}
        *{box-sizing:border-box;margin:0}
      `}</style>

      {notif && <div style={S.notif}><span>✓</span> {notif}</div>}

      <header style={{...S.header, borderBottomColor: rc}}>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <img src={LOGO_URL} alt="Vivalien" style={{height:36,width:"auto"}} />
          <span style={{...S.badge, background: rc+"14", color: rc}}>
            {{admin:"Admin",companion:"Compagnon",family:"Famille"}[role]}
          </span>
        </div>
        <div style={{display:"flex",alignItems:"center",gap:8}}>
          <span style={{fontSize:12,color:"#888"}}>{userData.name}</span>
          <button style={S.ghostBtn} onClick={() => signOut(auth)}>Déconnexion</button>
        </div>
      </header>

      <nav style={S.nav}>
        {role === "admin" && <>
          <NB icon="🏠" label="Accueil" on={view==="dashboard"} click={()=>nav("dashboard")} c={rc} />
          <NB icon="👥" label="Compagnons" on={view==="companions"} click={()=>nav("companions")} c={rc} />
          <NB icon="🧓" label="Seniors" on={view==="seniors"} click={()=>nav("seniors")} c={rc} />
          <NB icon="📅" label="Planning" on={view==="calendar"} click={()=>nav("calendar")} c={rc} />
          <NB icon="📋" label="Rapports" on={view==="reports"} click={()=>nav("reports")} c={rc} />
        </>}
        {role === "companion" && <>
          <NB icon="🏠" label="Accueil" on={view==="dashboard"} click={()=>nav("dashboard")} c={rc} />
          <NB icon="📋" label="Rapports" on={view==="reports"} click={()=>nav("reports")} c={rc} />
          <NB icon="📅" label="Planning" on={view==="calendar"} click={()=>nav("calendar")} c={rc} />
          <NB icon="👥" label="Seniors" on={view==="seniors"} click={()=>nav("seniors")} c={rc} />
        </>}
        {role === "family" && <>
          <NB icon="🏠" label="Accueil" on={view==="dashboard"} click={()=>nav("dashboard")} c={rc} />
          <NB icon="📋" label="Rapports" on={view==="reports"} click={()=>nav("reports")} c={rc} />
          <NB icon="📹" label="Visio" on={view==="visio"} click={()=>nav("visio")} c={rc} />
        </>}
      </nav>

      <main style={{padding:16,animation:"fadeUp 0.35s ease"}}>
        {/* ADMIN */}
        {role==="admin" && view==="dashboard" && <AdminDash reps={reports} seniors={seniors} companions={companions} events={events} />}
        {role==="admin" && view==="companions" && <CompanionsList companions={companions} reports={reports} seniors={seniors} />}
        {role==="admin" && view==="seniors" && !addSeniorMode && <SList seniors={seniors} onAdd={()=>setAddSeniorMode(true)} role="admin" companions={companions} />}
        {role==="admin" && view==="seniors" && addSeniorMode && <AddSenior companions={companions} onDone={()=>{setAddSeniorMode(false);toast("Senior ajouté(e) !");}} onCancel={()=>setAddSeniorMode(false)} />}
        {role==="admin" && view==="calendar" && <AdminCalendar events={events} seniors={seniors} companions={companions} toast={toast} />}
        {role==="admin" && view==="reports" && !sel && <RList reps={reports} onSel={setSel} />}
        {role==="admin" && view==="reports" && sel && <RDetail r={sel} back={()=>setSel(null)} role="admin" />}

        {/* COMPANION */}
        {role==="companion" && view==="dashboard" && <CDash reps={reports} seniors={seniors} events={events} onView={r=>{setSel(r);setView("reports")}} />}
        {role==="companion" && view==="reports" && !sel && !newMode && <RList reps={reports} onSel={setSel} onNew={()=>setNewMode(true)} />}
        {role==="companion" && view==="reports" && sel && <RDetail r={sel} back={()=>setSel(null)} role="companion" onSend={()=>toast("Compte-rendu envoyé !")} />}
        {role==="companion" && newMode && <NewReport seniors={seniors} userId={user.uid} onDone={()=>{setNewMode(false);setView("reports");toast("Rapport créé !");}} onCancel={()=>setNewMode(false)} />}
        {role==="companion" && view==="calendar" && <CompCalendar events={events} />}
        {role==="companion" && view==="seniors" && <SList seniors={seniors} role="companion" />}

        {/* FAMILY */}
        {role==="family" && view==="dashboard" && <FDash reps={reports} seniors={seniors} onView={r=>{setSel(r);setView("reports")}} />}
        {role==="family" && view==="reports" && !sel && <RList reps={reports} onSel={setSel} />}
        {role==="family" && view==="reports" && sel && <RDetail r={sel} back={()=>setSel(null)} role="family" />}
        {role==="family" && view==="visio" && <Visio reports={reports} />}
      </main>
    </div>
  );
}

// ================================================================
// LOADING + AUTH
// ================================================================
function LoadScreen() {
  return (
    <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",background:"#FAFCF8",fontFamily:"'Source Sans 3',sans-serif"}}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@700;800&family=Source+Sans+3:wght@400;600&display=swap');
        @keyframes spin{to{transform:rotate(360deg)}}`}</style>
      <img src={LOGO_URL} alt="Vivalien" style={{width:100,height:"auto",marginBottom:16}} />
      <div style={{width:32,height:32,border:"3px solid #E8F5E9",borderTopColor:"#2E7D32",borderRadius:"50%",animation:"spin 0.8s linear infinite"}} />
    </div>
  );
}

function AuthScreen({ toast }) {
  const [mode, setMode] = useState("login");
  const [email, setEmail] = useState("");
  const [pass, setPass] = useState("");
  const [role, setRole] = useState("companion");
  const [name, setName] = useState("");
  const [error, setError] = useState("");
  const [busy, setBusy] = useState(false);

  const handleLogin = async () => {
    setError(""); setBusy(true);
    try { await signInWithEmailAndPassword(auth, email, pass); }
    catch (e) {
      if (e.code === "auth/user-not-found") setError("Aucun compte avec cet email.");
      else if (e.code === "auth/wrong-password" || e.code === "auth/invalid-credential") setError("Mot de passe incorrect.");
      else setError("Erreur de connexion.");
    }
    setBusy(false);
  };

  const handleRegister = async () => {
    setError("");
    if (!name) { setError("Entrez votre nom."); return; }
    setBusy(true);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, pass);
      await setDoc(doc(db, "users", cred.user.uid), { email, name, role, createdAt: serverTimestamp() });
      toast("Compte créé !");
    } catch (e) {
      if (e.code === "auth/email-already-in-use") setError("Email déjà utilisé.");
      else if (e.code === "auth/weak-password") setError("Mot de passe trop court (6 caractères min).");
      else setError("Erreur lors de la création.");
    }
    setBusy(false);
  };

  const roles = [
    {id:"companion",label:"Compagnon",icon:"🌿"},
    {id:"family",label:"Famille",icon:"👨‍👩‍👧"},
  ];

  return (
    <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",padding:24,background:"linear-gradient(170deg,#FAFCF8 0%,#f0f7ff 100%)",fontFamily:"'Source Sans 3',sans-serif"}}>
      <style>{`@import url('https://fonts.googleapis.com/css2?family=Playfair+Display:wght@500;700;800&family=Source+Sans+3:wght@300;400;500;600;700&display=swap');*{box-sizing:border-box;margin:0}`}</style>
      <img src={LOGO_URL} alt="Vivalien" style={{width:140,height:"auto",marginBottom:8}} />
      <p style={{fontSize:14,color:"#666",fontStyle:"italic",marginBottom:32,textAlign:"center"}}>Un moment de compagnie, d'évasion, l'esprit tranquille.</p>

      <div style={{...S.card, padding:24, width:"100%", maxWidth:400}}>
        <div style={{display:"flex",marginBottom:24,borderRadius:12,overflow:"hidden",border:"1px solid #ddd"}}>
          <button onClick={()=>{setMode("login");setError("");}} style={{flex:1,padding:"10px",border:"none",cursor:"pointer",fontWeight:600,fontSize:14,background:mode==="login"?"#2E7D32":"#fff",color:mode==="login"?"#fff":"#555",fontFamily:"inherit"}}>Connexion</button>
          <button onClick={()=>{setMode("register");setError("");}} style={{flex:1,padding:"10px",border:"none",cursor:"pointer",fontWeight:600,fontSize:14,background:mode==="register"?"#2E7D32":"#fff",color:mode==="register"?"#fff":"#555",fontFamily:"inherit"}}>Inscription</button>
        </div>

        {mode === "register" && <>
          <label style={S.label}>Votre nom</label>
          <input style={S.input} placeholder="Prénom Nom" value={name} onChange={e=>setName(e.target.value)} />
          <label style={S.label}>Votre rôle</label>
          <div style={{display:"flex",gap:8,marginBottom:12}}>
            {roles.map(r => (
              <button key={r.id} onClick={()=>setRole(r.id)} style={{
                flex:1,padding:"12px 6px",border:`2px solid ${role===r.id?"#2E7D32":"#eee"}`,
                borderRadius:12,background:role===r.id?"#E8F5E915":"#fff",cursor:"pointer",textAlign:"center",transition:"all 0.2s",
              }}>
                <div style={{fontSize:22}}>{r.icon}</div>
                <div style={{fontSize:12,fontWeight:role===r.id?700:400,color:role===r.id?"#2E7D32":"#555",marginTop:4}}>{r.label}</div>
              </button>
            ))}
          </div>
        </>}

        <label style={S.label}>Email</label>
        <input style={S.input} type="email" placeholder="votre@email.com" value={email} onChange={e=>setEmail(e.target.value)} />
        <label style={S.label}>Mot de passe</label>
        <input style={S.input} type="password" placeholder="••••••••" value={pass} onChange={e=>setPass(e.target.value)}
          onKeyDown={e=>{ if(e.key==="Enter") mode==="login"?handleLogin():handleRegister(); }} />
        {error && <p style={{color:"#d32f2f",fontSize:13,marginTop:8}}>{error}</p>}
        <button style={{...S.btn,width:"100%",marginTop:20,opacity:busy?0.6:1}} disabled={busy}
          onClick={mode==="login"?handleLogin:handleRegister}>
          {busy ? "..." : mode==="login" ? "Se connecter" : "Créer mon compte"}
        </button>
      </div>
    </div>
  );
}

function NB({icon,label,on,click,c}) {
  return (
    <button onClick={click} style={{display:"flex",flexDirection:"column",alignItems:"center",gap:2,padding:"8px 10px",border:"none",background:on?`${c}12`:"transparent",cursor:"pointer",borderRadius:12,transition:"all 0.2s",color:on?c:"#888"}}>
      <span style={{fontSize:16}}>{icon}</span>
      <span style={{fontSize:10,fontWeight:600}}>{label}</span>
    </button>
  );
}

// ================================================================
// ADMIN DASHBOARD
// ================================================================
function AdminDash({ reps, seniors, companions, events }) {
  const upcoming = events.filter(e => new Date(e.date) >= new Date()).length;
  const monthReps = reps.filter(r => { const d = new Date(r.date); const n = new Date(); return d.getMonth()===n.getMonth() && d.getFullYear()===n.getFullYear(); });
  const ca = monthReps.length * 120;

  return (
    <div>
      <h2 style={S.h2}>Tableau de bord Admin</h2>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:24}}>
        <Stat v={companions.length} l="Compagnons" c="#6A1B9A" icon="🌿" />
        <Stat v={seniors.length} l="Seniors" c="#1565C0" icon="🧓" />
        <Stat v={monthReps.length} l="Rapports ce mois" c="#2E7D32" icon="📋" />
        <Stat v={ca+"€"} l="CA ce mois" c="#E65100" icon="💰" />
      </div>

      <h3 style={S.h3}>Activité par compagnon</h3>
      {companions.length === 0 && <p style={{color:"#888",fontSize:14}}>Aucun compagnon inscrit pour le moment.</p>}
      {companions.map(c => {
        const cReps = reps.filter(r => r.companionId === c.id);
        const cSeniors = seniors.filter(s => s.companionId === c.id);
        const cEvents = events.filter(e => e.companionId === c.id && new Date(e.date) >= new Date());
        return (
          <div key={c.id} style={{...S.card,padding:16,marginBottom:10}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <div>
                <div style={{fontWeight:700,fontSize:15,color:"#222"}}>{c.name}</div>
                <div style={{fontSize:12,color:"#888"}}>{c.email}</div>
              </div>
              <div style={{textAlign:"right"}}>
                <div style={{fontSize:12,color:"#6A1B9A",fontWeight:600}}>{cSeniors.length} seniors</div>
                <div style={{fontSize:12,color:"#2E7D32"}}>{cReps.length} rapports</div>
                <div style={{fontSize:12,color:"#E65100"}}>{cEvents.length} visites prévues</div>
              </div>
            </div>
          </div>
        );
      })}

      {reps.length > 0 && <h3 style={{...S.h3,marginTop:24}}>Derniers rapports</h3>}
      {reps.slice(0,3).map(r => <RC key={r.id} r={r} click={()=>{}} />)}
    </div>
  );
}

// ================================================================
// ADMIN — COMPANIONS LIST
// ================================================================
function CompanionsList({ companions, reports, seniors }) {
  return (
    <div>
      <h2 style={S.h2}>Compagnons ({companions.length})</h2>
      {companions.length === 0 && (
        <div style={{textAlign:"center",padding:32,color:"#888"}}>
          <p style={{fontSize:40,marginBottom:12}}>🌿</p>
          <p>Aucun compagnon inscrit. Ils doivent créer un compte avec le rôle "Compagnon".</p>
        </div>
      )}
      {companions.map(c => {
        const cReps = reports.filter(r => r.companionId === c.id);
        const cSeniors = seniors.filter(s => s.companionId === c.id);
        return (
          <div key={c.id} style={{...S.card,padding:20,marginBottom:12}}>
            <div style={{display:"flex",alignItems:"center",gap:14}}>
              <div style={{width:52,height:52,borderRadius:16,background:"linear-gradient(135deg,#E8F5E9,#C8E6C9)",color:"#2E7D32",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,fontWeight:700,flexShrink:0}}>{c.name?.[0]}</div>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,fontSize:16,color:"#222"}}>{c.name}</div>
                <div style={{fontSize:13,color:"#888"}}>{c.email}</div>
                <div style={{display:"flex",gap:8,marginTop:8}}>
                  <span style={S.tag}>{cSeniors.length} seniors</span>
                  <span style={{...S.tag,background:"#E3F2FD",color:"#1565C0"}}>{cReps.length} rapports</span>
                </div>
              </div>
            </div>
            {cSeniors.length > 0 && (
              <div style={{marginTop:12,paddingTop:12,borderTop:"1px solid #f0f0f0"}}>
                <div style={{fontSize:12,fontWeight:600,color:"#555",marginBottom:6}}>Seniors affectés :</div>
                {cSeniors.map(s => (
                  <div key={s.id} style={{fontSize:13,color:"#444",padding:"2px 0"}}>• {s.name} ({s.familyName})</div>
                ))}
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

// ================================================================
// ADMIN — CALENDAR (assign visits to any companion)
// ================================================================
function AdminCalendar({ events, seniors, companions, toast }) {
  const [adding, setAdding] = useState(false);
  const [newEv, setNewEv] = useState({ date: "", time: "09:00", seniorId: "", companionId: "" });

  const addEvent = async () => {
    if (!newEv.date || !newEv.seniorId || !newEv.companionId) return;
    const senior = seniors.find(s => s.id === newEv.seniorId);
    const comp = companions.find(c => c.id === newEv.companionId);
    await addDoc(collection(db, "events"), {
      companionId: newEv.companionId,
      companionName: comp?.name || "",
      seniorId: newEv.seniorId,
      seniorName: senior?.name || "",
      date: newEv.date,
      time: newEv.time,
      type: "visit",
    });
    setAdding(false);
    setNewEv({ date: "", time: "09:00", seniorId: "", companionId: "" });
    toast("Visite planifiée !");
  };

  const deleteEvent = async (id) => {
    await deleteDoc(doc(db, "events", id));
    toast("Visite supprimée");
  };

  const days = [];
  const start = new Date();
  start.setDate(start.getDate() - start.getDay() + 1);
  for(let i=0;i<14;i++){const d=new Date(start);d.setDate(d.getDate()+i);days.push(d);}
  const dn=["Dim","Lun","Mar","Mer","Jeu","Ven","Sam"];

  return (
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20}}>
        <h2 style={S.h2}>Planning général</h2>
        <button style={{...S.btn,background:"#6A1B9A"}} onClick={()=>setAdding(!adding)}>＋ Planifier</button>
      </div>

      {adding && (
        <div style={{...S.card,padding:16,marginBottom:16}}>
          <label style={S.label}>Compagnon *</label>
          <select style={S.input} value={newEv.companionId} onChange={e=>setNewEv({...newEv,companionId:e.target.value})}>
            <option value="">— Choisir un compagnon —</option>
            {companions.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
          <label style={S.label}>Senior *</label>
          <select style={S.input} value={newEv.seniorId} onChange={e=>setNewEv({...newEv,seniorId:e.target.value})}>
            <option value="">— Choisir un senior —</option>
            {seniors.filter(s => !newEv.companionId || s.companionId === newEv.companionId).map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
          <label style={S.label}>Date *</label>
          <input style={S.input} type="date" value={newEv.date} onChange={e=>setNewEv({...newEv,date:e.target.value})} />
          <label style={S.label}>Heure</label>
          <select style={S.input} value={newEv.time} onChange={e=>setNewEv({...newEv,time:e.target.value})}>
            <option value="09:00">09:00</option><option value="10:00">10:00</option>
            <option value="14:00">14:00</option><option value="15:00">15:00</option>
          </select>
          <button style={{...S.btn,width:"100%",marginTop:12,background:"#6A1B9A"}} onClick={addEvent}>✓ Planifier la visite</button>
        </div>
      )}

      {/* Calendar grid */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:5}}>
        {days.map((d,i)=>{
          const ds=d.toISOString().split("T")[0]; const evs=events.filter(e=>e.date===ds);
          const today=ds===new Date().toISOString().split("T")[0];
          return (
            <div key={i} style={{background:"#fff",borderRadius:10,padding:6,minHeight:90,boxShadow:"0 1px 4px rgba(0,0,0,0.05)",...(today?{border:"2px solid #6A1B9A",background:"#F3E5F5"}:{}),opacity:evs.length?1:0.4}}>
              <div style={{fontSize:10,color:"#888",fontWeight:600,textAlign:"center"}}>{dn[d.getDay()]}</div>
              <div style={{fontSize:14,fontWeight:700,textAlign:"center",color:today?"#6A1B9A":"#333",marginBottom:3}}>{d.getDate()}</div>
              {evs.map((ev,j)=>(
                <div key={j} style={{borderRadius:6,padding:"3px 4px",marginTop:3,textAlign:"center",background:"#E8F5E9",color:"#2E7D32",position:"relative",cursor:"pointer"}}
                  onClick={()=>{ if(window.confirm(`Supprimer la visite de ${ev.seniorName} ?`)) deleteEvent(ev.id); }}>
                  <div style={{fontSize:10,fontWeight:600}}>{ev.time}</div>
                  <div style={{fontSize:9}}>{ev.seniorName?.split(" ")[0]}</div>
                  <div style={{fontSize:8,color:"#888"}}>{ev.companionName?.split(" ")[0]}</div>
                </div>
              ))}
            </div>
          );
        })}
      </div>

      {/* List view */}
      <h3 style={{...S.h3,marginTop:24}}>Prochaines visites</h3>
      {events.filter(e=>new Date(e.date)>=new Date()).sort((a,b)=>a.date.localeCompare(b.date)).slice(0,10).map(ev => (
        <div key={ev.id} style={{...S.card,display:"flex",alignItems:"center",gap:12,padding:12,marginBottom:8}}>
          <div style={{width:10,height:10,borderRadius:"50%",background:"#2E7D32",flexShrink:0}} />
          <div style={{flex:1}}>
            <div style={{fontWeight:600,fontSize:14,color:"#222"}}>{ev.seniorName}</div>
            <div style={{fontSize:12,color:"#888"}}>{fd(ev.date)} à {ev.time}</div>
            <div style={{fontSize:11,color:"#6A1B9A"}}>Compagnon : {ev.companionName}</div>
          </div>
          <button onClick={()=>{ if(window.confirm("Supprimer ?")) deleteEvent(ev.id); }} style={{border:"none",background:"none",cursor:"pointer",fontSize:16,color:"#d32f2f"}}>🗑</button>
        </div>
      ))}
    </div>
  );
}

// ================================================================
// COMPANION CALENDAR (read-only)
// ================================================================
function CompCalendar({ events }) {
  const days = [];
  const start = new Date();
  start.setDate(start.getDate() - start.getDay() + 1);
  for(let i=0;i<14;i++){const d=new Date(start);d.setDate(d.getDate()+i);days.push(d);}
  const dn=["Dim","Lun","Mar","Mer","Jeu","Ven","Sam"];

  return (
    <div>
      <h2 style={S.h2}>Mon planning</h2>
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:6}}>
        {days.map((d,i)=>{
          const ds=d.toISOString().split("T")[0]; const evs=events.filter(e=>e.date===ds);
          const today=ds===new Date().toISOString().split("T")[0];
          return (
            <div key={i} style={{background:"#fff",borderRadius:12,padding:8,minHeight:95,boxShadow:"0 1px 4px rgba(0,0,0,0.05)",...(today?{border:"2px solid #2E7D32",background:"#FAFCF8"}:{}),opacity:evs.length?1:0.4}}>
              <div style={{fontSize:11,color:"#888",fontWeight:600,textAlign:"center"}}>{dn[d.getDay()]}</div>
              <div style={{fontSize:16,fontWeight:700,textAlign:"center",color:today?"#2E7D32":"#333",marginBottom:4}}>{d.getDate()}</div>
              {evs.map((ev,j)=>(
                <div key={j} style={{borderRadius:8,padding:"4px 5px",marginTop:4,textAlign:"center",background:"#E8F5E9",color:"#2E7D32"}}>
                  <div style={{fontSize:11,fontWeight:600}}>{ev.time}</div>
                  <div style={{fontSize:10}}>{ev.seniorName?.split(" ")[0]}</div>
                </div>
              ))}
            </div>
          );
        })}
      </div>
      <h3 style={{...S.h3,marginTop:24}}>Mes prochaines visites</h3>
      {events.filter(e=>new Date(e.date)>=new Date()).sort((a,b)=>a.date.localeCompare(b.date)).map(ev => (
        <div key={ev.id} style={{...S.card,display:"flex",alignItems:"center",gap:12,padding:14,marginBottom:8}}>
          <div style={{width:10,height:10,borderRadius:"50%",background:"#2E7D32",flexShrink:0}} />
          <div>
            <div style={{fontWeight:600,fontSize:14,color:"#222"}}>{ev.seniorName}</div>
            <div style={{fontSize:12,color:"#888"}}>{fd(ev.date)} à {ev.time}</div>
          </div>
        </div>
      ))}
    </div>
  );
}

