function CDash({ reps, seniors, events, onView }) {
  const upcoming = events.filter(e => new Date(e.date) >= new Date()).slice(0, 3);
  const monthRevenue = reps.filter(r => { const d=new Date(r.date); const n=new Date(); return d.getMonth()===n.getMonth()&&d.getFullYear()===n.getFullYear(); }).length * 120;
  return (
    <div>
      <h2 style={S.h2}>Bonjour ! Voici ton résumé</h2>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:24}}>
        <Stat v={reps.length} l="Rapports" c="#2E7D32" icon="📋" />
        <Stat v={seniors.length} l="Seniors" c="#1565C0" icon="👥" />
        <Stat v={upcoming.length} l="Visites à venir" c="#E65100" icon="📅" />
        <Stat v={monthRevenue+"€"} l="CA ce mois" c="#7B1FA2" icon="💰" />
      </div>
      {upcoming.length > 0 && <h3 style={S.h3}>Prochaines visites</h3>}
      {upcoming.map(ev => (
        <div key={ev.id} style={{...S.card,display:"flex",alignItems:"center",gap:12,padding:14,marginBottom:8}}>
          <div style={{width:10,height:10,borderRadius:"50%",background:"#2E7D32",flexShrink:0}} />
          <div>
            <div style={{fontWeight:600,fontSize:14,color:"#222"}}>{ev.seniorName}</div>
            <div style={{fontSize:12,color:"#888"}}>{fd(ev.date)} à {ev.time}</div>
          </div>
        </div>
      ))}
      {reps.length > 0 && <h3 style={{...S.h3,marginTop:24}}>Derniers rapports</h3>}
      {reps.slice(0,2).map(r => <RC key={r.id} r={r} click={() => onView(r)} />)}
      {reps.length===0 && seniors.length===0 && <div style={{textAlign:"center",padding:32,color:"#888"}}><p style={{fontSize:40,marginBottom:12}}>👋</p><p>L'admin va bientôt t'affecter des seniors !</p></div>}
    </div>
  );
}

function Stat({ v, l, c, icon }) {
  return (
    <div style={{background:"#fff",borderRadius:16,padding:"16px 14px",borderLeft:`4px solid ${c}`,boxShadow:"0 2px 10px rgba(0,0,0,0.05)"}}>
      <div style={{fontSize:20,marginBottom:4}}>{icon}</div>
      <div style={{fontSize:28,fontWeight:800,color:c,fontFamily:"'Playfair Display',serif"}}>{v}</div>
      <div style={{fontSize:12,color:"#888",marginTop:2}}>{l}</div>
    </div>
  );
}

